class Solution {
    public List<Integer> beautifulIndices(String s, String a, String b, int k) {
        List<Integer> res = new ArrayList<>();
        int n = s.length(), mA = a.length(), mB = b.length();
        if (mA > n || mB > n) return res;

        List<Integer> aIdx = kmp(s, a);
        List<Integer> bIdx = kmp(s, b);
        if (aIdx.isEmpty() || bIdx.isEmpty()) return res;

        int j = 0, lenB = bIdx.size();
        for (int i : aIdx) {
            while (j < lenB && bIdx.get(j) < i - k) j++;
            if (j < lenB && Math.abs(bIdx.get(j) - i) <= k) {
                res.add(i);
                continue;
            }
            if (j > 0 && Math.abs(bIdx.get(j - 1) - i) <= k) {
                res.add(i);
            }
        }
        return res;
    }

    private List<Integer> kmp(String text, String pat) {
        List<Integer> res = new ArrayList<>();
        int n = text.length(), m = pat.length();
        if (m == 0 || n < m) return res;
        int[] lps = buildLPS(pat);
        int i = 0, j = 0;
        while (i < n) {
            if (text.charAt(i) == pat.charAt(j)) {
                i++; j++;
                if (j == m) {
                    res.add(i - j);
                    j = lps[j - 1];
                }
            } else {
                if (j != 0) j = lps[j - 1];
                else i++;
            }
        }
        return res;
    }

    private int[] buildLPS(String pat) {
        int m = pat.length();
        int[] lps = new int[m];
        for (int i = 1, len = 0; i < m; ) {
            if (pat.charAt(i) == pat.charAt(len)) {
                lps[i++] = ++len;
            } else if (len != 0) {
                len = lps[len - 1];
            } else {
                lps[i++] = 0;
            }
        }
        return lps;
    }
}
